namespace sv_4d5c213546e2453d8cc60ea3b29f551e.Models;

public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

@page "/apply"
@rendermode InteractiveServer
@using sv_4d5c213546e2453d8cc60ea3b29f551e.Models
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<h1 class="mb-4">Job Application</h1>

@if (!_submitted)
{
    <!-- Step Indicator Bar -->
    <nav class="mb-4">
        <ol class="d-flex list-unstyled gap-2 flex-wrap align-items-center step-indicator">
            @for (int i = 0; i < _stepLabels.Length; i++)
            {
                var stepIndex = i;
                var isCurrent = stepIndex == _currentStep;
                var isCompleted = stepIndex < _currentStep;
                var isFuture = stepIndex > _currentStep;

                <li class="d-flex align-items-center gap-1">
                    @if (isCompleted)
                    {
                        <button class="btn btn-sm btn-success rounded-pill px-3"
                                @onclick="() => GoToStep(stepIndex)">
                            ✓ @_stepLabels[stepIndex]
                        </button>
                    }
                    else if (isCurrent)
                    {
                        <span class="btn btn-sm btn-primary rounded-pill px-3 fw-bold">
                            @($"{stepIndex + 1}. {_stepLabels[stepIndex]}")
                        </span>
                    }
                    else
                    {
                        <span class="btn btn-sm btn-outline-secondary rounded-pill px-3 disabled opacity-50">
                            @($"{stepIndex + 1}. {_stepLabels[stepIndex]}")
                        </span>
                    }

                    @if (stepIndex < _stepLabels.Length - 1)
                    {
                        <span class="text-muted">→</span>
                    }
                </li>
            }
        </ol>
    </nav>

    <!-- Validation errors -->
    @if (_errors.Count > 0)
    {
        <div class="alert alert-danger">
            <ul class="mb-0">
                @foreach (var error in _errors)
                {
                    <li>@error</li>
                }
            </ul>
        </div>
    }

    <!-- Step 1: Personal Info -->
    @if (_currentStep == 0)
    {
        <div class="card">
            <div class="card-header"><h4 class="mb-0">Personal Information</h4></div>
            <div class="card-body">
                <div class="mb-3">
                    <label class="form-label">Full Name <span class="text-danger">*</span></label>
                    <input class="form-control" @bind="_fullName" placeholder="Enter your full name" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Email <span class="text-danger">*</span></label>
                    <input type="email" class="form-control" @bind="_email" placeholder="you@example.com" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Phone <span class="text-danger">*</span></label>
                    <input type="tel" class="form-control" @bind="_phone" placeholder="(555) 123-4567" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Address <span class="text-danger">*</span></label>
                    <textarea class="form-control" @bind="_address" rows="2" placeholder="Street, City, State, ZIP"></textarea>
                </div>
                <div class="d-flex justify-content-end">
                    <button class="btn btn-primary" @onclick="NextStep" disabled="@_isValidating">
                        @if (_isValidating)
                        {
                            <span class="spinner-border spinner-border-sm me-1"></span>
                            <span>Validating…</span>
                        }
                        else
                        {
                            <span>Next →</span>
                        }
                    </button>
                </div>
            </div>
        </div>
    }

    <!-- Step 2: Work History -->
    @if (_currentStep == 1)
    {
        <div class="card">
            <div class="card-header"><h4 class="mb-0">Work History</h4></div>
            <div class="card-body">
                @for (int i = 0; i < _workEntries.Count; i++)
                {
                    var index = i;
                    var entry = _workEntries[index];
                    <div class="border rounded p-3 mb-3 bg-light">
                        <div class="d-flex justify-content-between align-items-center mb-2">
                            <h5 class="mb-0">Position @(index + 1)</h5>
                            @if (_workEntries.Count > 1)
                            {
                                <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveWorkEntry(index)">Remove</button>
                            }
                        </div>
                        <div class="row mb-2">
                            <div class="col-md-6">
                                <label class="form-label">Company Name <span class="text-danger">*</span></label>
                                <input class="form-control" @bind="entry.Company" placeholder="Company name" />
                            </div>
                            <div class="col-md-6">
                                <label class="form-label">Job Title <span class="text-danger">*</span></label>
                                <input class="form-control" @bind="entry.Title" placeholder="Job title" />
                            </div>
                        </div>
                        <div class="row mb-2">
                            <div class="col-md-4">
                                <label class="form-label">Start Date <span class="text-danger">*</span></label>
                                <input type="date" class="form-control" @bind="entry.StartDate" />
                            </div>
                            <div class="col-md-4">
                                <label class="form-label">End Date</label>
                                <input type="date" class="form-control" @bind="entry.EndDate" disabled="@entry.IsCurrent" />
                            </div>
                            <div class="col-md-4 d-flex align-items-end">
                                <div class="form-check mb-2">
                                    <input type="checkbox" class="form-check-input" id="@($"current-{index}")"
                                           @bind="entry.IsCurrent" />
                                    <label class="form-check-label" for="@($"current-{index}")">Currently working here</label>
                                </div>
                            </div>
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Description</label>
                            <textarea class="form-control" @bind="entry.Description" rows="2"
                                      placeholder="Describe your responsibilities and achievements"></textarea>
                        </div>
                    </div>
                }
                <button class="btn btn-outline-primary mb-3" @onclick="AddWorkEntry">+ Add Another Position</button>
                <div class="d-flex justify-content-between">
                    <button class="btn btn-secondary" @onclick="PreviousStep">← Back</button>
                    <button class="btn btn-primary" @onclick="NextStep">Next →</button>
                </div>
            </div>
        </div>
    }

    <!-- Step 3: References -->
    @if (_currentStep == 2)
    {
        <div class="card">
            <div class="card-header"><h4 class="mb-0">References</h4></div>
            <div class="card-body">
                @for (int i = 0; i < _references.Count; i++)
                {
                    var index = i;
                    var reference = _references[index];
                    <div class="border rounded p-3 mb-3 bg-light">
                        <div class="d-flex justify-content-between align-items-center mb-2">
                            <h5 class="mb-0">Reference @(index + 1)</h5>
                            @if (_references.Count > 2)
                            {
                                <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveReference(index)">Remove</button>
                            }
                        </div>
                        <div class="row mb-2">
                            <div class="col-md-6">
                                <label class="form-label">Name <span class="text-danger">*</span></label>
                                <input class="form-control" @bind="reference.Name" placeholder="Reference name" />
                            </div>
                            <div class="col-md-6">
                                <label class="form-label">Relationship <span class="text-danger">*</span></label>
                                <input class="form-control" @bind="reference.Relationship" placeholder="e.g. Former Manager" />
                            </div>
                        </div>
                        <div class="row mb-2">
                            <div class="col-md-6">
                                <label class="form-label">Email <span class="text-danger">*</span></label>
                                <input type="email" class="form-control" @bind="reference.Email" placeholder="email@example.com" />
                            </div>
                            <div class="col-md-6">
                                <label class="form-label">Phone <span class="text-danger">*</span></label>
                                <input type="tel" class="form-control" @bind="reference.Phone" placeholder="(555) 123-4567" />
                            </div>
                        </div>
                    </div>
                }
                @if (_references.Count < 3)
                {
                    <button class="btn btn-outline-primary mb-3" @onclick="AddReference">+ Add Reference</button>
                }
                <div class="d-flex justify-content-between">
                    <button class="btn btn-secondary" @onclick="PreviousStep">← Back</button>
                    <button class="btn btn-primary" @onclick="NextStep">Next →</button>
                </div>
            </div>
        </div>
    }

    <!-- Step 4: Cover Letter -->
    @if (_currentStep == 3)
    {
        <div class="card">
            <div class="card-header"><h4 class="mb-0">Cover Letter</h4></div>
            <div class="card-body">
                <div class="mb-3">
                    <label class="form-label">Write your cover letter <span class="text-danger">*</span></label>
                    <textarea class="form-control" @bind="_coverLetter" @bind:event="oninput"
                              rows="10" maxlength="2000"
                              placeholder="Tell us why you're a great fit for this role…"></textarea>
                    <div class="form-text text-end">
                        @(_coverLetter?.Length ?? 0) / 2000 characters
                    </div>
                </div>
                <div class="d-flex justify-content-between">
                    <button class="btn btn-secondary" @onclick="PreviousStep">← Back</button>
                    <button class="btn btn-primary" @onclick="NextStep">Next →</button>
                </div>
            </div>
        </div>
    }

    <!-- Step 5: Review & Submit -->
    @if (_currentStep == 4)
    {
        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <h4 class="mb-0">Personal Information</h4>
                <button class="btn btn-sm btn-link" @onclick="() => GoToStep(0)">Edit</button>
            </div>
            <div class="card-body">
                <dl class="row mb-0">
                    <dt class="col-sm-3">Full Name</dt><dd class="col-sm-9">@_fullName</dd>
                    <dt class="col-sm-3">Email</dt><dd class="col-sm-9">@_email</dd>
                    <dt class="col-sm-3">Phone</dt><dd class="col-sm-9">@_phone</dd>
                    <dt class="col-sm-3">Address</dt><dd class="col-sm-9">@_address</dd>
                </dl>
            </div>
        </div>

        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <h4 class="mb-0">Work History</h4>
                <button class="btn btn-sm btn-link" @onclick="() => GoToStep(1)">Edit</button>
            </div>
            <div class="card-body">
                @foreach (var entry in _workEntries)
                {
                    <div class="mb-3 pb-3 border-bottom">
                        <strong>@entry.Title</strong> at <strong>@entry.Company</strong><br />
                        <span class="text-muted">
                            @entry.StartDate.ToString("MMM yyyy") –
                            @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")
                        </span>
                        @if (!string.IsNullOrWhiteSpace(entry.Description))
                        {
                            <p class="mt-1 mb-0">@entry.Description</p>
                        }
                    </div>
                }
            </div>
        </div>

        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <h4 class="mb-0">References</h4>
                <button class="btn btn-sm btn-link" @onclick="() => GoToStep(2)">Edit</button>
            </div>
            <div class="card-body">
                @foreach (var r in _references)
                {
                    <div class="mb-2">
                        <strong>@r.Name</strong> — @r.Relationship<br />
                        <span class="text-muted">@r.Email · @r.Phone</span>
                    </div>
                }
            </div>
        </div>

        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <h4 class="mb-0">Cover Letter</h4>
                <button class="btn btn-sm btn-link" @onclick="() => GoToStep(3)">Edit</button>
            </div>
            <div class="card-body">
                <p style="white-space: pre-wrap;">@_coverLetter</p>
            </div>
        </div>

        <div class="d-flex justify-content-between">
            <button class="btn btn-secondary" @onclick="PreviousStep">← Back</button>
            <button class="btn btn-success btn-lg" @onclick="SubmitApplication" disabled="@_isSubmitting">
                @if (_isSubmitting)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                    <span>Submitting…</span>
                }
                else
                {
                    <span>Submit Application</span>
                }
            </button>
        </div>
    }
}
else
{
    <!-- Confirmation -->
    <div class="text-center py-5">
        <div class="mb-3">
            <span class="display-1 text-success">✓</span>
        </div>
        <h2 class="text-success">Application Submitted!</h2>
        <p class="lead">Your application has been received successfully.</p>
        <p>Your application ID is: <strong class="fs-4">@_applicationId</strong></p>
        <p class="text-muted">Please save this ID for your records.</p>
        <a href="/apply" class="btn btn-primary mt-3">Submit Another Application</a>
    </div>
}

@code {
    private readonly string[] _stepLabels = { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };
    private int _currentStep;
    private List<string> _errors = new();
    private bool _isValidating;
    private bool _isSubmitting;
    private bool _submitted;
    private int _applicationId;

    // Step 1
    private string _fullName = string.Empty;
    private string _email = string.Empty;
    private string _phone = string.Empty;
    private string _address = string.Empty;

    // Step 2
    private List<WorkEntryModel> _workEntries = new() { new() };

    // Step 3
    private List<ReferenceModel> _references = new() { new(), new() };

    // Step 4
    private string _coverLetter = string.Empty;

    private void GoToStep(int step)
    {
        if (step < _currentStep)
        {
            _errors.Clear();
            _currentStep = step;
        }
    }

    private void PreviousStep()
    {
        _errors.Clear();
        if (_currentStep > 0) _currentStep--;
    }

    private async Task NextStep()
    {
        _errors.Clear();

        if (!ValidateCurrentStep())
            return;

        if (_currentStep == 0)
        {
            _isValidating = true;
            try
            {
                var isValid = await ApplicationService.ValidateEmailAsync(_email);
                if (!isValid)
                {
                    _errors.Add("The email address could not be validated. Please use a different email.");
                    return;
                }
            }
            finally
            {
                _isValidating = false;
            }
        }

        _currentStep++;
    }

    private bool ValidateCurrentStep()
    {
        switch (_currentStep)
        {
            case 0:
                if (string.IsNullOrWhiteSpace(_fullName)) _errors.Add("Full name is required.");
                if (string.IsNullOrWhiteSpace(_email)) _errors.Add("Email is required.");
                if (string.IsNullOrWhiteSpace(_phone)) _errors.Add("Phone is required.");
                if (string.IsNullOrWhiteSpace(_address)) _errors.Add("Address is required.");
                break;

            case 1:
                for (int i = 0; i < _workEntries.Count; i++)
                {
                    var e = _workEntries[i];
                    if (string.IsNullOrWhiteSpace(e.Company)) _errors.Add($"Position {i + 1}: Company name is required.");
                    if (string.IsNullOrWhiteSpace(e.Title)) _errors.Add($"Position {i + 1}: Job title is required.");
                    if (e.StartDate == default) _errors.Add($"Position {i + 1}: Start date is required.");
                }
                break;

            case 2:
                for (int i = 0; i < _references.Count; i++)
                {
                    var r = _references[i];
                    if (string.IsNullOrWhiteSpace(r.Name)) _errors.Add($"Reference {i + 1}: Name is required.");
                    if (string.IsNullOrWhiteSpace(r.Relationship)) _errors.Add($"Reference {i + 1}: Relationship is required.");
                    if (string.IsNullOrWhiteSpace(r.Email)) _errors.Add($"Reference {i + 1}: Email is required.");
                    if (string.IsNullOrWhiteSpace(r.Phone)) _errors.Add($"Reference {i + 1}: Phone is required.");
                }
                break;

            case 3:
                if (string.IsNullOrWhiteSpace(_coverLetter)) _errors.Add("Cover letter is required.");
                break;
        }

        return _errors.Count == 0;
    }

    private void AddWorkEntry() => _workEntries.Add(new WorkEntryModel());

    private void RemoveWorkEntry(int index)
    {
        if (_workEntries.Count > 1) _workEntries.RemoveAt(index);
    }

    private void AddReference()
    {
        if (_references.Count < 3) _references.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (_references.Count > 2) _references.RemoveAt(index);
    }

    private async Task SubmitApplication()
    {
        _isSubmitting = true;
        _errors.Clear();

        try
        {
            var personal = new PersonalInfo(_fullName, _email, _phone, _address);

            var workHistory = new WorkHistory(_workEntries.Select(e =>
                new WorkEntry(e.Company, e.Title, e.StartDate, e.IsCurrent ? null : e.EndDate, e.Description ?? string.Empty)
            ).ToList());

            var references = _references.Select(r =>
                new Reference(r.Name, r.Relationship, r.Email, r.Phone)
            ).ToList();

            var application = new JobApplication(personal, workHistory, references, _coverLetter);
            _applicationId = await ApplicationService.SubmitApplicationAsync(application);
            _submitted = true;
        }
        catch (Exception ex)
        {
            _errors.Add($"Submission failed: {ex.Message}");
        }
        finally
        {
            _isSubmitting = false;
        }
    }

    private class WorkEntryModel
    {
        public string Company { get; set; } = string.Empty;
        public string Title { get; set; } = string.Empty;
        public DateTime StartDate { get; set; }
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string? Description { get; set; }
    }

    private class ReferenceModel
    {
        public string Name { get; set; } = string.Empty;
        public string Relationship { get; set; } = string.Empty;
        public string Email { get; set; } = string.Empty;
        public string Phone { get; set; } = string.Empty;
